module mux4to1(
    input [7:0] data_in_0,
    input [7:0] in1,
    input [7:0] in2,
    input [7:0] in3,
    input [1:0] sel,
    output reg [7:0] mux_out
);
    always @(*) begin
        case (sel)
            2'b00: mux_out = data_in_0;
            2'b01: mux_out = in1;
            2'b10: mux_out = in2;
            2'b11: mux_out = in3;
            default: mux_out = 8'd0;
        endcase
    end
endmodule
